using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

// EF9 Cosmos DB breaking changes — fixes for existing documents using "Discriminator" property
// and synchronous queries.

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change #1: Default discriminator property renamed from
        // "Discriminator" to "$type". Existing documents use the old name.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // EF9 breaking change #2: id property no longer contains the discriminator.
        // Existing documents have "Session|<key>" format. Preserve old format so
        // existing documents remain accessible.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
}

// EF9 breaking change #3: Sync I/O on Cosmos DB provider now throws.
// All synchronous calls must be converted to async equivalents.
class CosmosQueryService
{
    private readonly CosmosDbContext _db;

    public CosmosQueryService(CosmosDbContext db) => _db = db;

    // BEFORE (throws in EF9):
    //   var sessions = _db.Sessions.Where(s => s.Name == name).ToList();
    //   _db.SaveChanges();

    // AFTER (async equivalents):
    public async Task<List<Session>> GetSessionsAsync(string name, CancellationToken ct = default)
    {
        return await _db.Sessions
            .Where(s => s.Name == name)
            .ToListAsync(ct);
    }

    public async Task SaveAsync(CancellationToken ct = default)
    {
        await _db.SaveChangesAsync(ct);
    }
}

